    digitalWrite(rightmotor, LOW);
    digitalWrite(rightmotor1, HIGH);
    delay(2000);
    digitalWrite(leftmotor, LOW);//RIGHT
    digitalWrite(leftmotor1, HIGH);
    digitalWrite(rightmotor, HIGH);
    digitalWrite(rightmotor1, LOW);
    delay(2000);
  }
}

